//#region src/private/prismUtils.ts
const DEFAULT_LANGUAGE = "text";
const DISPLAY_LANGUAGE_REPLACEMENTS = {
	"splunk-spl": "Splunk SPL",
	csharp: "C#",
	fsharp: "F#",
	graphql: "GraphQL",
	html: "HTML",
	http: "HTTP",
	javascript: "JavaScript",
	json: "JSON",
	jsx: "JSX",
	php: "PHP",
	sql: "SQL",
	toml: "TOML",
	tsx: "TSX",
	typescript: "TypeScript",
	yaml: "YAML"
};
const PRISM_LANGUAGE_REPLACEMENTS = {
	"c#": "csharp",
	cs: "csharp",
	dotnet: "csharp",
	gql: "graphql",
	js: "javascript",
	jsonc: "json",
	md: "markdown",
	sh: "bash",
	shell: "bash",
	splunk: "splunk-spl",
	ts: "typescript",
	vb: "visual-basic",
	vba: "visual-basic",
	yml: "yaml"
};
const titleCase = (kebabcased) => kebabcased.split("-").map((segment) => segment ? `${segment[0].toLocaleUpperCase()}${segment.slice(1)}` : segment).join(" ");
const prismLanguage = (language) => {
	const lower = (language ?? DEFAULT_LANGUAGE).toLocaleLowerCase();
	return PRISM_LANGUAGE_REPLACEMENTS[lower] ?? lower;
};
const displayLanguage = (language) => {
	const prism = prismLanguage(language);
	return DISPLAY_LANGUAGE_REPLACEMENTS[prism] ?? titleCase(prism);
};
//#endregion
export { displayLanguage, prismLanguage };
